// Call before declaration — works because of hoisting
const result = add(3, 5); // 8

function add(a, b) {
  return a + b;
}

// Recursive declaration — function can refer to itself by name
function factorial(n) {
  if (n <= 1) return 1;
  return n * factorial(n - 1);
}

factorial(5); // 120

// Cannot call before assignment
// greet('Alice'); // TypeError or ReferenceError

const greet = function(name) {
  return `Hello, ${name}!`;
};

greet('Alice'); // 'Hello, Alice!'

// Named function expression — name is accessible inside the function
const countdown = function countDown(n) {
  if (n <= 0) return;
  console.log(n);
  countDown(n - 1); // can use 'countDown' here
};

// Concise body — implicit return when no braces
const double = x => x * 2;
const add = (a, b) => a + b;
const greet = name => `Hello, ${name}!`;

// Block body — explicit return required
const processUser = (user) => {
  const name = user.name.trim();
  return { ...user, name };
};

// Returning an object literal — wrap in parentheses to avoid parse ambiguity
const toPoint = (x, y) => ({ x, y });

// No parameters — empty parentheses required
const getRandom = () => Math.random();

// Arrow function in callbacks — inherits this correctly
class Timer {
  elapsed = 0;
  start() {
    setInterval(() => {
      this.elapsed++; // 'this' is the Timer instance — works!
    }, 1000);
  }
}

function createUser(name, role = 'viewer', active = true) {
  return { name, role, active };
}

createUser('Alice');                    // { name:'Alice', role:'viewer', active:true }
createUser('Bob', 'admin');             // { name:'Bob',  role:'admin',  active:true }
createUser('Carol', undefined, false);  // role uses default, active is false

// Default can reference earlier parameters
function buildRange(start, end = start + 10) {
  return { start, end };
}
buildRange(5); // { start: 5, end: 15 }

// Default can be any expression, including function calls
function getTimeout(ms = Date.now() % 1000) { ... }

function sum(...numbers) {
  return numbers.reduce((acc, n) => acc + n, 0);
}
sum(1, 2, 3, 4); // 10

function log(level, ...messages) {
  console[level](...messages);
}
log('warn', 'Something', 'went', 'wrong'); // console.warn('Something', 'went', 'wrong')

// TypeScript: rest with type
function join(separator: string, ...parts: string[]): string {
  return parts.join(separator);
}

// Object destructuring in parameters
function displayUser({ name, role, age = 0 }) {
  console.log(`${name} (${role}), age ${age}`);
}
displayUser({ name: 'Alice', role: 'admin' }); // 'Alice (admin), age 0'

// Array destructuring in parameters
function swap([a, b]) {
  return [b, a];
}
swap([1, 2]); // [2, 1]

// Angular: common in reactive forms and ngOnChanges
ngOnChanges({ title, value }: SimpleChanges) {
  if (title?.currentValue) { ... }
  if (value?.currentValue !== value?.previousValue) { ... }
}

// Nested destructuring with defaults
function configureChart({
  width = 300,
  height = 200,
  margin: { top = 10, right = 10, bottom = 10, left = 10 } = {},
} = {}) {
  // all config values available directly
}

const obj = {
  name: 'Widget',
  greet() {
    console.log(this.name);   // 'Widget' — method call, this = obj
  },
  greetArrow: () => {
    console.log(this.name);   // undefined — arrow, inherits outer this
  },
};

// Losing this — common mistake
const detached = obj.greet;
detached();            // undefined (or error in strict) — no calling object

// Fixing with bind
const bound = obj.greet.bind(obj);
bound();               // 'Widget'

// call / apply
obj.greet.call({ name: 'Other' }); // 'Other'
obj.greet.apply({ name: 'Apply' }); // 'Apply'

@Component({ selector: 'app-counter', template: '{{ count }}' })
export class CounterComponent {
  count = 0;

  increment() {
    this.count++;   // this = component instance when called via event binding
  }

  startAutoIncrement() {
    // Arrow function — this is captured from the class instance
    setInterval(() => this.count++, 1000);

    // Regular function — this would be undefined in strict mode
    // setInterval(function() { this.count++; }, 1000); // WRONG
  }
}

// Takes a function — array.map is higher-order
[1, 2, 3].map(x => x * 2); // [2, 4, 6]

// Returns a function — factory / currying
function multiplier(factor) {
  return (n) => n * factor;  // returned function closes over factor
}
const triple = multiplier(3);
triple(5); // 15
triple(7); // 21

// Composition — combine small functions
const compose = (...fns) => x => fns.reduceRight((v, f) => f(v), x);
const pipe    = (...fns) => x => fns.reduce((v, f) => f(v), x);

const process = pipe(
  str => str.trim(),
  str => str.toLowerCase(),
  str => str.replace(/\s+/g, '-'),
);
process('  Hello World  '); // 'hello-world'

// Memoization — cache results by argument
function memoize(fn) {
  const cache = new Map();
  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) return cache.get(key);
    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

const expensiveCalc = memoize((n) => {
  // ... slow computation
  return n * n;
});

// Pure — predictable, testable
const add = (a, b) => a + b;
const capitalize = str => str.charAt(0).toUpperCase() + str.slice(1);
const toDisplayUser = user => ({ ...user, fullName: `${user.first} ${user.last}` });

// Impure — has side effects or non-deterministic
let counter = 0;
const increment = () => counter++;              // mutates external state
const getRandom = () => Math.random();          // non-deterministic
const fetchUser = async id => await api(id);    // I/O side effect

// Angular: use pure functions in pipes for performance
// Angular's change detection only re-evaluates a pure pipe when its input reference changes
@Pipe({ name: 'discount', pure: true })
export class DiscountPipe implements PipeTransform {
  transform(price: number, rate: number): number {
    return price * (1 - rate); // pure — no external state
  }
}

// Classic IIFE — creates private scope
(function() {
  const privateVar = 'only here';
  // ...
})();

// Arrow IIFE
(() => {
  // ...
})();

// Async IIFE — run async code at module top level (pre-ES2022 top-level await)
(async () => {
  const data = await fetchInitialData();
  initializeApp(data);
})();

function* counter(start = 0) {
  let i = start;
  while (true) {
    yield i++;
  }
}

const gen = counter(1);
gen.next().value; // 1
gen.next().value; // 2
gen.next().value; // 3

// Finite generator — iterable with for...of
function* range(start, end, step = 1) {
  for (let i = start; i <= end; i += step) {
    yield i;
  }
}

for (const n of range(1, 5)) console.log(n); // 1 2 3 4 5
[...range(0, 10, 2)]; // [0, 2, 4, 6, 8, 10]

@Injectable({ providedIn: 'root' })
export class AuthService {
  private user: User | null = null;

  // Regular method — this is the service instance
  login(credentials: Credentials): Observable<User> {
    return this.http.post<User>('/api/login', credentials).pipe(
      tap(user => this.user = user),   // arrow in tap — this is AuthService
    );
  }

  isLoggedIn(): boolean {
    return this.user !== null;
  }

  // Getter — function without ()
  get currentUser(): User | null {
    return this.user;
  }
}

// Pure function guard — no class needed
export const authGuard = (): boolean | UrlTree => {
  const auth   = inject(AuthService);
  const router = inject(Router);
  return auth.isLoggedIn() || router.createUrlTree(['/login']);
};

// Functional guard with parameters — returns a guard function
export const roleGuard = (requiredRole: string) => (): boolean | UrlTree => {
  const auth   = inject(AuthService);
  const router = inject(Router);
  const user   = auth.currentUser;
  return (user?.role === requiredRole) || router.createUrlTree(['/forbidden']);
};

// In routing
{
  path: 'admin',
  canActivate: [authGuard, roleGuard('admin')],
  component: AdminComponent,
}

// Partial application — fix some arguments, return function for the rest
function partial(fn, ...presetArgs) {
  return function(...laterArgs) {
    return fn(...presetArgs, ...laterArgs);
  };
}

const multiply = (a, b) => a * b;
const double   = partial(multiply, 2);
const triple   = partial(multiply, 3);
double(5);  // 10
triple(5);  // 15

// Currying — transform f(a, b) into f(a)(b)
const curry = fn => a => b => fn(a, b);
const curriedAdd = curry((a, b) => a + b);
const add5 = curriedAdd(5);
add5(3); // 8
add5(7); // 12

// Angular: parameterised validators
function minLength(min: number): ValidatorFn {
  return (control: AbstractControl) => {
    return control.value?.length >= min
      ? null
      : { minLength: { required: min, actual: control.value?.length } };
  };
}

// In a form
Validators.compose([minLength(3), minLength(8)]);
// FormControl('', [minLength(8)])

// Overload signatures — listed first
function formatDate(date: Date): string;
function formatDate(timestamp: number): string;
function formatDate(isoString: string): string;

// Implementation — must handle all overload cases
function formatDate(input: Date | number | string): string {
  const d = input instanceof Date
    ? input
    : new Date(input);
  return d.toLocaleDateString('en-US');
}

// TypeScript knows these are valid:
formatDate(new Date());      // Date overload
formatDate(1710000000000);   // number overload
formatDate('2024-03-10');    // string overload

// Overloads in Angular service
class ChartService {
  render(data: number[]): void;
  render(data: ChartData): void;
  render(data: number[] | ChartData): void {
    const normalized = Array.isArray(data) ? { values: data } : data;
    // ...
  }
}

// async function — always returns Promise<T>
async function loadUser(id: string): Promise<User> {
  const response = await fetch(`/api/users/${id}`);
  if (!response.ok) throw new Error(`HTTP ${response.status}`);
  return response.json();
}

// Arrow async function
const loadProduct = async (id: string): Promise<Product> => {
  const res = await fetch(`/api/products/${id}`);
  return res.json();
};

// Sequential vs parallel
async function sequential() {
  const user    = await loadUser('1');    // waits for user
  const product = await loadProduct('2'); // then waits for product
  return { user, product };
}

async function parallel() {
  const [user, product] = await Promise.all([
    loadUser('1'),    // both start simultaneously
    loadProduct('2'),
  ]);
  return { user, product };
}

// Angular HttpClient already returns Observable — async/await is for native fetch
// Use firstValueFrom to bridge Observable → Promise when needed
async function getUserOnce(id: string): Promise<User> {
  return firstValueFrom(this.http.get<User>(\`/api/users/\${id}\`));
}

@Injectable({ providedIn: 'root' })
export class DataService {
  constructor(private http: HttpClient) {}

  // Most Angular code uses RxJS Observable, not async/await
  getUsers(): Observable<User[]> {
    return this.http.get<User[]>('/api/users');
  }

  // Async/await works for one-shot operations
  async initializeApp(): Promise<void> {
    try {
      const config = await firstValueFrom(this.http.get<AppConfig>('/api/config'));
      this.applyConfig(config);
    } catch (err) {
      console.error('Init failed:', err);
    }
  }
}

// Pure function — trivial to test
function formatCurrency(amount: number, currency = 'USD'): string {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(amount);
}

describe('formatCurrency', () => {
  it('formats USD by default', () => {
    expect(formatCurrency(1234.5)).toBe('$1,234.50');
  });
  it('formats EUR', () => {
    expect(formatCurrency(100, 'EUR')).toBe('€100.00');
  });
  it('handles zero', () => {
    expect(formatCurrency(0)).toBe('$0.00');
  });
});

// Testing a function with side effects — spy on the dependency
describe('UserService.login', () => {
  it('stores user on success', async () => {
    const http = jasmine.createSpyObj('HttpClient', { post: of(mockUser) });
    const service = new AuthService(http);
    await firstValueFrom(service.login(credentials));
    expect(service.currentUser).toEqual(mockUser);
  });
});
